//! User mock fixtures loaded from `.shatter/config.yaml`.
//!
//! Provides [`MockValueSpace`] policy (FixedSet, Autonomous, Seeded, LiveFirst)
//! with hierarchical scoping (global, file, function) and type validation at
//! load time. Post-execution expectations (`called_with`, `call_count`) let
//! users assert mock interactions.

use std::collections::HashMap;
use std::fmt;

use serde::{Deserialize, Serialize};
use serde_json::Value;

use crate::types::TypeInfo;

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/// Maximum number of return values in a single FixedSet before we warn.
pub const MAX_FIXED_SET_VALUES: usize = 1000;

/// Default call-count expectation lower bound when not specified.
pub const DEFAULT_MIN_CALL_COUNT: u32 = 0;

/// Separator between file path and function name in scoped keys.
pub const SCOPE_SEPARATOR: &str = "::";

// ---------------------------------------------------------------------------
// MockValueSpace — how mock return values are sourced
// ---------------------------------------------------------------------------

/// Policy controlling where a mock's return values come from.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "mode", rename_all = "snake_case")]
pub enum MockValueSpace {
    /// Return values cycle through a user-supplied fixed set.
    FixedSet {
        values: Vec<Value>,
    },
    /// Engine generates values autonomously (type-aware random).
    Autonomous,
    /// Engine generates values seeded from user-supplied examples.
    Seeded {
        seeds: Vec<Value>,
    },
    /// Try the real implementation first; fall back to fixture on error.
    LiveFirst {
        fallback: Vec<Value>,
    },
}

impl Default for MockValueSpace {
    fn default() -> Self {
        Self::Autonomous
    }
}

// ---------------------------------------------------------------------------
// MockExpectation — post-execution assertions
// ---------------------------------------------------------------------------

/// A pattern for matching call arguments (used in `called_with` expectations).
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(untagged)]
pub enum ArgPattern {
    /// Match an exact value.
    Exact(Value),
    /// Match any value (represented as the string `"_"` in YAML).
    Any,
}

impl ArgPattern {
    /// Check whether a runtime argument matches this pattern.
    pub fn matches(&self, actual: &Value) -> bool {
        match self {
            Self::Exact(expected) => expected == actual,
            Self::Any => true,
        }
    }
}

/// A single call-argument expectation: the mock must have been called with
/// arguments matching these patterns at least once.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct CalledWithExpectation {
    /// Argument patterns; length must match the callee's arity.
    pub args: Vec<ArgPattern>,
}

/// Call-count expectation: the mock must have been called within the given range.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct CallCountExpectation {
    /// Minimum number of times the mock must be called (inclusive).
    #[serde(default)]
    pub min: Option<u32>,
    /// Maximum number of times the mock may be called (inclusive).
    #[serde(default)]
    pub max: Option<u32>,
    /// Exact number of times the mock must be called (overrides min/max).
    #[serde(default)]
    pub exact: Option<u32>,
}

impl CallCountExpectation {
    /// Check whether `actual` call count satisfies this expectation.
    pub fn satisfied_by(&self, actual: u32) -> bool {
        if let Some(exact) = self.exact {
            return actual == exact;
        }
        let min = self.min.unwrap_or(DEFAULT_MIN_CALL_COUNT);
        let max = self.max.unwrap_or(u32::MAX);
        actual >= min && actual <= max
    }
}

/// Post-execution expectations for a single mock symbol.
#[derive(Debug, Clone, Default, PartialEq, Serialize, Deserialize)]
pub struct MockExpectation {
    /// The mock must have been called with arguments matching at least one of these patterns.
    #[serde(default)]
    pub called_with: Vec<CalledWithExpectation>,
    /// Call-count constraint.
    #[serde(default)]
    pub call_count: Option<CallCountExpectation>,
}

// ---------------------------------------------------------------------------
// MockFixture — a single mock definition at any scope
// ---------------------------------------------------------------------------

/// A user-defined mock fixture for a single symbol.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct MockFixture {
    /// The dependency symbol being mocked (e.g. `"db.query"`).
    pub symbol: String,
    /// How return values are sourced.
    #[serde(default)]
    pub value_space: MockValueSpace,
    /// Optional expected return type for load-time validation.
    #[serde(default)]
    pub return_type: Option<TypeInfo>,
    /// Post-execution expectations.
    #[serde(default)]
    pub expectations: Option<MockExpectation>,
}

// ---------------------------------------------------------------------------
// Scoping
// ---------------------------------------------------------------------------

/// Scope at which a mock fixture applies.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum MockScope {
    /// Applies to all functions in all files.
    Global,
    /// Applies to all functions in a specific file.
    File(String),
    /// Applies to a specific function in a specific file.
    Function {
        file: String,
        function: String,
    },
}

impl MockScope {
    /// Parse a scope key from a YAML config key.
    ///
    /// - `"*"` or `""` → Global
    /// - `"src/auth.ts"` (no `::`) → File
    /// - `"src/auth.ts::validateToken"` → Function
    pub fn parse(key: &str) -> Self {
        let trimmed = key.trim();
        if trimmed.is_empty() || trimmed == "*" {
            return Self::Global;
        }
        if let Some((file, func)) = trimmed.split_once(SCOPE_SEPARATOR) {
            Self::Function {
                file: file.to_string(),
                function: func.to_string(),
            }
        } else {
            Self::File(trimmed.to_string())
        }
    }

    /// Check whether this scope matches a given file path and function name.
    pub fn matches(&self, file: &str, function: &str) -> bool {
        match self {
            Self::Global => true,
            Self::File(f) => file.ends_with(f.as_str()),
            Self::Function { file: f, function: func } => {
                file.ends_with(f.as_str()) && function == func
            }
        }
    }
}

impl fmt::Display for MockScope {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::Global => write!(f, "*"),
            Self::File(path) => write!(f, "{path}"),
            Self::Function { file, function } => write!(f, "{file}{SCOPE_SEPARATOR}{function}"),
        }
    }
}

// ---------------------------------------------------------------------------
// MockFixtureSet — all fixtures at all scopes
// ---------------------------------------------------------------------------

/// Collection of mock fixtures organized by scope.
#[derive(Debug, Clone, Default, PartialEq, Serialize, Deserialize)]
pub struct MockFixtureSet {
    /// Global fixtures (apply to all functions).
    #[serde(default)]
    pub global: Vec<MockFixture>,
    /// File-scoped fixtures, keyed by file path.
    #[serde(default)]
    pub files: HashMap<String, Vec<MockFixture>>,
    /// Function-scoped fixtures, keyed by `"file::function"`.
    #[serde(default)]
    pub functions: HashMap<String, Vec<MockFixture>>,
}

impl MockFixtureSet {
    /// Resolve all applicable fixtures for a given file + function, in priority order:
    /// function-scoped (highest) > file-scoped > global (lowest).
    ///
    /// When the same symbol appears at multiple scopes, the narrowest scope wins.
    pub fn resolve_for(&self, file: &str, function: &str) -> Vec<&MockFixture> {
        let mut seen: HashMap<&str, &MockFixture> = HashMap::new();

        // Global (lowest priority)
        for fixture in &self.global {
            seen.insert(fixture.symbol.as_str(), fixture);
        }

        // File-scoped (overrides global)
        for (key, fixtures) in &self.files {
            if file.ends_with(key.as_str()) {
                for fixture in fixtures {
                    seen.insert(fixture.symbol.as_str(), fixture);
                }
            }
        }

        // Function-scoped (highest priority) — exact key match
        let func_key = format!("{file}{SCOPE_SEPARATOR}{function}");
        if let Some(fixtures) = self.functions.get(&func_key) {
            for fixture in fixtures {
                seen.insert(fixture.symbol.as_str(), fixture);
            }
        }
        // Also try suffix matching for function keys
        for (key, fixtures) in &self.functions {
            if let Some((f, func)) = key.split_once(SCOPE_SEPARATOR) {
                if file.ends_with(f) && function == func {
                    for fixture in fixtures {
                        seen.insert(fixture.symbol.as_str(), fixture);
                    }
                }
            }
        }

        seen.into_values().collect()
    }
}

// ---------------------------------------------------------------------------
// Type validation
// ---------------------------------------------------------------------------

/// A type mismatch found during load-time validation.
#[derive(Debug, Clone, PartialEq)]
pub struct TypeMismatch {
    pub scope: String,
    pub symbol: String,
    pub expected: TypeInfo,
    pub actual_value: Value,
    pub message: String,
}

impl fmt::Display for TypeMismatch {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(
            f,
            "[{}] mock '{}': {}",
            self.scope, self.symbol, self.message
        )
    }
}

/// Check whether a JSON value is compatible with a TypeInfo.
///
/// Returns `Ok(())` if the value is valid for the type, or an error message.
pub fn validate_value_type(value: &Value, expected: &TypeInfo) -> Result<(), String> {
    match (value, expected) {
        (Value::Null, TypeInfo::Nullable { .. }) => Ok(()),
        (Value::Null, _) => Err(format!("expected {expected:?}, got null")),

        (Value::Bool(_), TypeInfo::Bool) => Ok(()),
        (Value::Bool(_), _) => Err(format!("expected {expected:?}, got boolean")),

        (Value::Number(n), TypeInfo::Int) => {
            if n.is_i64() || n.is_u64() {
                Ok(())
            } else {
                Err(format!("expected integer, got {n}"))
            }
        }
        (Value::Number(_), TypeInfo::Float) => Ok(()),
        (Value::Number(n), _) => Err(format!("expected {expected:?}, got number {n}")),

        (Value::String(_), TypeInfo::Str) => Ok(()),
        (Value::String(s), _) => Err(format!("expected {expected:?}, got string \"{s}\"")),

        (Value::Array(items), TypeInfo::Array { element }) => {
            for (i, item) in items.iter().enumerate() {
                validate_value_type(item, element)
                    .map_err(|e| format!("array[{i}]: {e}"))?;
            }
            Ok(())
        }
        (Value::Array(_), _) => Err(format!("expected {expected:?}, got array")),

        (Value::Object(obj), TypeInfo::Object { fields }) => {
            for (name, field_type) in fields {
                match obj.get(name) {
                    Some(val) => validate_value_type(val, field_type)
                        .map_err(|e| format!("field '{name}': {e}"))?,
                    None => {
                        if !matches!(field_type, TypeInfo::Nullable { .. }) {
                            return Err(format!("missing required field '{name}'"));
                        }
                    }
                }
            }
            Ok(())
        }
        (Value::Object(_), _) => Err(format!("expected {expected:?}, got object")),
    }
}

/// Validate all fixtures in a set against their declared return types.
///
/// Returns a list of all type mismatches found. An empty list means all fixtures
/// pass validation.
pub fn validate_fixture_set(set: &MockFixtureSet) -> Vec<TypeMismatch> {
    let mut mismatches = Vec::new();

    let scoped_fixtures: Vec<(String, &MockFixture)> = set
        .global
        .iter()
        .map(|f| ("*".to_string(), f))
        .chain(
            set.files
                .iter()
                .flat_map(|(k, fs)| fs.iter().map(move |f| (k.clone(), f))),
        )
        .chain(
            set.functions
                .iter()
                .flat_map(|(k, fs)| fs.iter().map(move |f| (k.clone(), f))),
        )
        .collect();

    for (scope_key, fixture) in scoped_fixtures {
        let Some(ref expected_type) = fixture.return_type else {
            continue;
        };

        let values_to_check = match &fixture.value_space {
            MockValueSpace::FixedSet { values } => values.as_slice(),
            MockValueSpace::Seeded { seeds } => seeds.as_slice(),
            MockValueSpace::LiveFirst { fallback } => fallback.as_slice(),
            MockValueSpace::Autonomous => continue,
        };

        for (i, value) in values_to_check.iter().enumerate() {
            if let Err(msg) = validate_value_type(value, expected_type) {
                mismatches.push(TypeMismatch {
                    scope: scope_key.clone(),
                    symbol: fixture.symbol.clone(),
                    expected: expected_type.clone(),
                    actual_value: value.clone(),
                    message: format!("value[{i}]: {msg}"),
                });
            }
        }
    }

    mismatches
}

// ---------------------------------------------------------------------------
// Expectation validation (post-execution)
// ---------------------------------------------------------------------------

/// A single expectation violation found after execution.
#[derive(Debug, Clone, PartialEq)]
pub struct ExpectationViolation {
    pub symbol: String,
    pub kind: ViolationKind,
}

/// What kind of expectation was violated.
#[derive(Debug, Clone, PartialEq)]
pub enum ViolationKind {
    /// call_count was outside the expected range.
    CallCount {
        expected: CallCountExpectation,
        actual: u32,
    },
    /// None of the actual calls matched a `called_with` pattern.
    CalledWith {
        pattern: CalledWithExpectation,
    },
}

impl fmt::Display for ExpectationViolation {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match &self.kind {
            ViolationKind::CallCount { expected, actual } => {
                if let Some(exact) = expected.exact {
                    write!(
                        f,
                        "'{}': expected exactly {exact} calls, got {actual}",
                        self.symbol
                    )
                } else {
                    let min = expected.min.unwrap_or(DEFAULT_MIN_CALL_COUNT);
                    let max = expected.max.unwrap_or(u32::MAX);
                    write!(
                        f,
                        "'{}': expected {min}..={max} calls, got {actual}",
                        self.symbol
                    )
                }
            }
            ViolationKind::CalledWith { pattern } => {
                write!(
                    f,
                    "'{}': never called with pattern {:?}",
                    self.symbol, pattern.args
                )
            }
        }
    }
}

/// Recorded calls for a mock symbol during execution.
#[derive(Debug, Clone, Default)]
pub struct MockCallRecord {
    /// Each entry is one call's argument list.
    pub calls: Vec<Vec<Value>>,
}

impl MockCallRecord {
    pub fn call_count(&self) -> u32 {
        self.calls.len() as u32
    }
}

/// Validate expectations against actual call records.
///
/// Returns all violations found. An empty list means all expectations are met.
pub fn validate_expectations(
    fixtures: &[&MockFixture],
    records: &HashMap<String, MockCallRecord>,
) -> Vec<ExpectationViolation> {
    let mut violations = Vec::new();

    for fixture in fixtures {
        let Some(ref expectations) = fixture.expectations else {
            continue;
        };

        let record = records.get(&fixture.symbol);
        let actual_count = record.map_or(0, |r| r.call_count());

        // Check call_count
        if let Some(ref cc) = expectations.call_count {
            if !cc.satisfied_by(actual_count) {
                violations.push(ExpectationViolation {
                    symbol: fixture.symbol.clone(),
                    kind: ViolationKind::CallCount {
                        expected: cc.clone(),
                        actual: actual_count,
                    },
                });
            }
        }

        // Check called_with patterns
        for pattern in &expectations.called_with {
            let matched = record.map_or(false, |r| {
                r.calls.iter().any(|call_args| {
                    call_args.len() == pattern.args.len()
                        && call_args
                            .iter()
                            .zip(&pattern.args)
                            .all(|(actual, pat)| pat.matches(actual))
                })
            });
            if !matched {
                violations.push(ExpectationViolation {
                    symbol: fixture.symbol.clone(),
                    kind: ViolationKind::CalledWith {
                        pattern: pattern.clone(),
                    },
                });
            }
        }
    }

    violations
}

