    // -- Property-based tests --

    mod proptests {
        use super::*;
        use proptest::prelude::*;

        fn arb_value_space() -> impl Strategy<Value = MockValueSpace> {
            prop_oneof![
                Just(MockValueSpace::Autonomous),
                prop::collection::vec(
                    prop_oneof![
                        Just(json!(null)),
                        Just(json!(42)),
                        Just(json!("hello")),
                        Just(json!(true)),
                        Just(json!([1, 2])),
                    ],
                    0..5,
                )
                .prop_map(|values| MockValueSpace::FixedSet { values }),
                prop::collection::vec(
                    prop_oneof![
                        Just(json!(null)),
                        Just(json!(42)),
                        Just(json!("seed")),
                    ],
                    1..4,
                )
                .prop_map(|seeds| MockValueSpace::Seeded { seeds }),
                prop::collection::vec(
                    prop_oneof![Just(json!(null)), Just(json!(0)),],
                    0..3,
                )
                .prop_map(|fallback| MockValueSpace::LiveFirst { fallback }),
            ]
        }

        fn arb_call_count() -> impl Strategy<Value = CallCountExpectation> {
            prop_oneof![
                (0u32..100).prop_map(|n| CallCountExpectation {
                    min: None,
                    max: None,
                    exact: Some(n),
                }),
                (0u32..50, 50u32..100).prop_map(|(min, max)| CallCountExpectation {
                    min: Some(min),
                    max: Some(max),
                    exact: None,
                }),
            ]
        }

        fn arb_mock_fixture() -> impl Strategy<Value = MockFixture> {
            (
                "[a-z][a-z.]{0,10}",
                arb_value_space(),
            )
                .prop_map(|(symbol, value_space)| MockFixture {
                    symbol,
                    value_space,
                    return_type: None,
                    expectations: None,
                })
        }

        proptest! {
            /// MockValueSpace survives YAML roundtrip.
            #[test]
            fn value_space_yaml_roundtrip(vs in arb_value_space()) {
                let yaml = serde_yaml::to_string(&vs).expect("serialize");
                let back: MockValueSpace = serde_yaml::from_str(&yaml).expect("deserialize");
                prop_assert_eq!(vs, back);
            }

            /// MockFixture survives YAML roundtrip.
            #[test]
            fn fixture_yaml_roundtrip(f in arb_mock_fixture()) {
                let yaml = serde_yaml::to_string(&f).expect("serialize");
                let back: MockFixture = serde_yaml::from_str(&yaml).expect("deserialize");
                prop_assert_eq!(f, back);
            }

            /// CallCountExpectation satisfies its own boundaries.
            #[test]
            fn call_count_self_consistent(cc in arb_call_count()) {
                if let Some(exact) = cc.exact {
                    prop_assert!(cc.satisfied_by(exact));
                    if exact > 0 {
                        prop_assert!(!cc.satisfied_by(exact - 1));
                    }
                } else {
                    let min = cc.min.unwrap_or(DEFAULT_MIN_CALL_COUNT);
                    let max = cc.max.unwrap_or(u32::MAX);
                    prop_assert!(cc.satisfied_by(min));
                    prop_assert!(cc.satisfied_by(max));
                    if min > 0 {
                        prop_assert!(!cc.satisfied_by(min - 1));
                    }
                    if max < u32::MAX {
                        prop_assert!(!cc.satisfied_by(max + 1));
                    }
                }
            }

            /// MockScope roundtrip: parse(display(scope)) preserves semantics.
            #[test]
            fn scope_display_parse_roundtrip(
                file in "[a-z/]{1,15}\\.[a-z]{1,3}",
                func in "[a-zA-Z_][a-zA-Z0-9_]{0,10}",
            ) {
                let scope = MockScope::Function { file: file.clone(), function: func.clone() };
                let displayed = scope.to_string();
                let parsed = MockScope::parse(&displayed);
                prop_assert_eq!(scope, parsed);

                let file_scope = MockScope::File(file.clone());
                let displayed2 = file_scope.to_string();
                let parsed2 = MockScope::parse(&displayed2);
                prop_assert_eq!(file_scope, parsed2);
            }

            /// Type validation: valid values pass, swapped types fail.
            #[test]
            fn type_validation_int_string_disjoint(n in -1000i64..1000) {
                let int_val = json!(n);
                let str_val = json!(format!("{n}"));
                prop_assert!(validate_value_type(&int_val, &TypeInfo::Int).is_ok());
                prop_assert!(validate_value_type(&str_val, &TypeInfo::Str).is_ok());
                prop_assert!(validate_value_type(&int_val, &TypeInfo::Str).is_err());
                prop_assert!(validate_value_type(&str_val, &TypeInfo::Int).is_err());
            }

            /// Resolved fixtures never exceed the number of distinct symbols.
            #[test]
            fn resolve_deduplicates_by_symbol(
                symbols in prop::collection::vec("[a-z]{1,5}", 1..5),
            ) {
                let global: Vec<MockFixture> = symbols.iter().map(|s| MockFixture {
                    symbol: s.clone(),
                    value_space: MockValueSpace::Autonomous,
                    return_type: None,
                    expectations: None,
                }).collect();

                let set = MockFixtureSet {
                    global,
                    files: HashMap::new(),
                    functions: HashMap::new(),
                };

                let resolved = set.resolve_for("any.ts", "anyFn");
                let unique_symbols: std::collections::HashSet<&str> =
                    symbols.iter().map(|s| s.as_str()).collect();
                prop_assert!(resolved.len() <= unique_symbols.len());
            }
        }
    }
